package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_null_callsNullValue() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.value((String) null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  public void value_nonNull_callsDeferredName_beforeValue_and_string() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    JsonWriter spyWriter = spy(jsonWriter);

    // Prepare deferredName to test writeDeferredName invocation effect
    spyWriter.name("aName");

    // Use reflection to access private methods
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);
    Method string = JsonWriter.class.getDeclaredMethod("string", String.class);
    string.setAccessible(true);

    doCallRealMethod().when(spyWriter).value(anyString());
    doCallRealMethod().when(spyWriter).writeDeferredName();
    doCallRealMethod().when(spyWriter).beforeValue();
    doCallRealMethod().when(spyWriter).string(anyString());

    JsonWriter result = spyWriter.value("testValue");

    // Verify methods called via spy
    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
    verify(spyWriter).string("testValue");

    assertSame(spyWriter, result);
    // The output should contain the string value with quotes
    String output = stringWriter.toString();
    assertTrue(output.contains("\"testValue\""));
  }

  @Test
  public void value_emptyString_writesEmptyQuotes() throws IOException {
    JsonWriter writer = new JsonWriter(stringWriter);
    writer.value("");
    String output = stringWriter.toString();
    assertTrue(output.contains("\"\""));
  }

  @Test
  public void value_multipleCalls_writesMultipleValues() throws IOException {
    JsonWriter writer = new JsonWriter(stringWriter);
    writer.beginArray();
    writer.value("one");
    writer.value("two");
    writer.endArray();

    String output = stringWriter.toString();
    assertEquals("[\"one\",\"two\"]", output);
  }

  @Test
  public void value_withDeferredName_writesNameAndValue() throws IOException {
    JsonWriter writer = new JsonWriter(stringWriter);
    writer.beginObject();
    writer.name("key");
    writer.value("val");
    writer.endObject();

    String output = stringWriter.toString();
    assertEquals("{\"key\":\"val\"}", output);
  }
}
